class OrderController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {
  def getOrderById(orderId: String): Action[AnyContent] = Action { request =>
    // Extract the order ID from the path parameter
    val orderIdParam = request.pathParams("orderId")

